import { run } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote â€” single item base premium
  it.todo("quotes a sword for a first-time customer (base + first-insurance + fee)");
  it.todo("quotes an amulet for a first-time customer");
  it.todo("quotes a staff for a first-time customer");
  it.todo("quotes a potion for a first-time customer");
  it.todo("quotes a single component (rune) at component base premium");

  // Components grouping
  it.todo("quotes three alike components as a block at the 60 G special premium");
  it.todo("quotes four alike components as one block of three plus one single");

  // Modifiers
  it.todo("adds a 50% surcharge for cursed items");
  it.todo("adds a 30% surcharge for highly enchanted items (level >= 5)");
  it.todo("applies a 20% loyalty discount for long-standing customers (>= 2 years)");
  it.todo("applies a 15% subsequent-contract discount on the second quote (no first-insurance surcharge)");
  it.todo("rounds the final premium up in MHPCO's favor");

  // Claim
  it.todo("pays out a regular claim minus the 100 G deductible after applying it");
  it.todo("reimburses damage to highly enchanted items (level >= 8) at 50%");
  it.todo("fully reimburses damage to items made of dragon material");

  // CLI integration (multi-step)
  it.todo("processes a scenario of a quote followed by a claim end-to-end");
});

