type Item = { type: string };
type Step = { op: "quote"; items: Item[] };
type Input = { customer: { yearsWithMHPCO: number }; steps: Step[] };

const basePremium = (type: string): number => {
  if (type === "amulet") return 60;
  return 100;
};

export const run = (input: Input): unknown => {
  const results = input.steps.map((step) => {
    const base = basePremium(step.items[0].type);
    const withFirst = base * 1.1;
    const premium = Math.ceil(withFirst + 5);
    return { premium };
  });
  return { results };
};

