const MAIN_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_SINGLE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;

const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);

const itemsBasePremium = (items: { type: string }[]): number => {
  let total = 0;
  const componentCounts: Record<string, number> = {};
  for (const item of items) {
    if (isComponent(item.type)) {
      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
    } else {
      total += MAIN_BASE_PREMIUMS[item.type];
    }
  }
  for (const count of Object.values(componentCounts)) {
    const blocks = Math.floor(count / 3);
    const singles = count % 3;
    total += blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_SINGLE_PREMIUM;
  }
  return total;
};

