  it.todo("reimburses damage to highly enchanted items (level >= 8) at 50%");
  it.todo("fully reimburses damage to items made of dragon material");

  // CLI integration (multi-step)
  it.todo("processes a scenario of a quote followed by a claim end-to-end");
});

