const MAIN_BASE_PREMIUMS: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune"]);
const COMPONENT_SINGLE_PREMIUM = 25;
const COMPONENT_BLOCK_PREMIUM = 60;
const COMPONENT_BLOCK_SIZE = 3;

const CURSED_SURCHARGE = 0.5;
const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
const HIGH_ENCHANTMENT_THRESHOLD = 5;

const isComponent = (type: string): boolean => COMPONENT_TYPES.has(type);

const componentsPremium = (count: number): number => {
  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
  const singles = count % COMPONENT_BLOCK_SIZE;
  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_SINGLE_PREMIUM;
};

const itemSurcharge = (item: Item): number => {
  let surcharge = 0;
  if (item.cursed) surcharge += CURSED_SURCHARGE;
  if ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD) {
    surcharge += HIGH_ENCHANTMENT_SURCHARGE;
  }
  return surcharge;
};

const itemPremium = (item: Item): number => {
  const base = isComponent(item.type)
    ? COMPONENT_SINGLE_PREMIUM
    : MAIN_BASE_PREMIUMS[item.type];
  return base * (1 + itemSurcharge(item));
};

const itemsBasePremium = (items: Item[]): number => {
  const mainItems = items.filter((item) => !isComponent(item.type));
  const components = items.filter((item) => isComponent(item.type));
  const mainTotal = mainItems.reduce((sum, item) => sum + itemPremium(item), 0);
  return mainTotal + componentsPremium(components.length);
};

const roundUp = (value: number): number => {
  const epsilon = 1e-9;
  return Math.ceil(value - epsilon);
};

