  // Quote â€” single item base premium
  it("quotes a sword for a first-time customer (base + first-insurance + fee)", () => {
    const output = run({
      customer: { yearsWithMHPCO: 0 },
      steps: [
        {
          op: "quote",
          items: [
            { type: "sword", material: "steel", enchantment: 3, cursed: false },
          ],
        },
      ],
