1	// --- Domain types ---
2	
3	type Item = {
4	  type: string;
5	  material?: string;
6	  enchantment?: number;
7	  cursed?: boolean;
8	};
9	
10	type Damage = { itemType: string; amount: number };
11	type Incident = { cause: string; damages: Damage[] };
12	
13	type QuoteStep = { op: "quote"; items: Item[] };
14	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
15	type Step = QuoteStep | ClaimStep;
16	
17	type Customer = { yearsWithMHPCO: number };
18	type Input = { customer: Customer; steps: Step[] };
19	
20	type QuoteResult = { premium: number };
21	type ClaimResult = { payout: number };
22	
23	// --- Pricing constants ---
24	
25	const BASE_PREMIUMS: Record<string, number> = {
26	  sword: 100,
27	  amulet: 60,
28	  staff: 80,
29	  potion: 40,
30	};
31	
32	const COMPONENT_TYPE = "rune";
33	const COMPONENT_SINGLE_PREMIUM = 25;
34	const COMPONENT_BLOCK_PREMIUM = 60;
35	const COMPONENT_BLOCK_SIZE = 3;
36	
37	const CURSED_SURCHARGE = 0.5;
38	const HIGH_ENCHANTMENT_QUOTE_SURCHARGE = 0.3;
39	const HIGH_ENCHANTMENT_QUOTE_THRESHOLD = 5;
40	
41	const FIRST_INSURANCE_SURCHARGE = 0.1;
42	const SUBSEQUENT_CONTRACT_DISCOUNT = 0.15;
43	const LOYALTY_DISCOUNT = 0.2;
44	const LOYALTY_THRESHOLD_YEARS = 2;
45	const PROCESSING_FEE = 5;
46	
47	const DEDUCTIBLE = 100;
48	const HIGH_ENCHANTMENT_PAYOUT_RATIO = 0.5;
49	const HIGH_ENCHANTMENT_CLAIM_THRESHOLD = 8;
50	const DRAGON_MATERIAL = "dragon";
51	
52	// --- Quote pricing ---
53	
54	const isComponent = (item: Item): boolean => item.type === COMPONENT_TYPE;
55	
56	const componentsPremium = (count: number): number => {
57	  const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
58	  const singles = count % COMPONENT_BLOCK_SIZE;
59	  return blocks * COMPONENT_BLOCK_PREMIUM + singles * COMPONENT_SINGLE_PREMIUM;
60	};
61	
62	const itemSurcharge = (item: Item): number => {
63	  const cursed = item.cursed ? CURSED_SURCHARGE : 0;
64	  const highlyEnchanted =
65	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_QUOTE_THRESHOLD
66	      ? HIGH_ENCHANTMENT_QUOTE_SURCHARGE
67	      : 0;
68	  return cursed + highlyEnchanted;
69	};
70	
71	const mainItemPremium = (item: Item): number =>
72	  BASE_PREMIUMS[item.type] * (1 + itemSurcharge(item));
73	
74	const itemsBasePremium = (items: Item[]): number => {
75	  const componentCount = items.filter(isComponent).length;
76	  const mainTotal = items
77	    .filter((item) => !isComponent(item))
78	    .reduce((sum, item) => sum + mainItemPremium(item), 0);
79	  return mainTotal + componentsPremium(componentCount);
80	};
81	
82	const customerModifier = (customer: Customer, isFirstQuote: boolean): number => {
83	  const contractModifier = isFirstQuote
84	    ? FIRST_INSURANCE_SURCHARGE
85	    : -SUBSEQUENT_CONTRACT_DISCOUNT;
86	  const loyalty =
87	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS ? -LOYALTY_DISCOUNT : 0;
88	  return contractModifier + loyalty;
89	};
90	
91	const roundUpInFavorOfMHPCO = (value: number): number => {
92	  const epsilon = 1e-9;
93	  return Math.ceil(value - epsilon);
94	};
95	
96	const quote = (
97	  items: Item[],
98	  customer: Customer,
99	  isFirstQuote: boolean,
100	): QuoteResult => {
101	  const base = itemsBasePremium(items);
102	  const adjusted = base * (1 + customerModifier(customer, isFirstQuote));
103	  return { premium: roundUpInFavorOfMHPCO(adjusted) + PROCESSING_FEE };
104	};
105	
106	// --- Claim payout ---
107	
108	const reimbursementFor = (damage: Damage, policyItems: Item[]): number => {
109	  const insured = policyItems.find((item) => item.type === damage.itemType);
110	  if (insured?.material === DRAGON_MATERIAL) return damage.amount;
111	  if ((insured?.enchantment ?? 0) >= HIGH_ENCHANTMENT_CLAIM_THRESHOLD) {
112	    return damage.amount * HIGH_ENCHANTMENT_PAYOUT_RATIO;
113	  }
114	  return damage.amount;
115	};
116	
117	const claim = (incident: Incident, policyItems: Item[]): ClaimResult => {
118	  const reimbursement = incident.damages.reduce(
119	    (sum, damage) => sum + reimbursementFor(damage, policyItems),
120	    0,
121	  );
122	  return { payout: reimbursement - DEDUCTIBLE };
123	};
124	
125	// --- Scenario runner ---
126	
127	export const run = (input: Input): { results: (QuoteResult | ClaimResult)[] } => {
128	  let quoteCount = 0;
129	  const results = input.steps.map((step) => {
130	    if (step.op === "claim") {
131	      const policy = input.steps[step.policy] as QuoteStep;
132	      return claim(step.incident, policy.items);
133	    }
134	    const isFirstQuote = quoteCount === 0;
135	    quoteCount += 1;
136	    return quote(step.items, input.customer, isFirstQuote);
137	  });
138	  return { results };
139	};
